"""Test the ReAct agent with a primer design request."""
from agents.agent import rnai_agent

seq = ""

result = rnai_agent.invoke(
    {"messages": [("user", f"设计这段dsRNA序列的引物，序列：{seq}")]},
    config={"configurable": {"thread_id": "test-agent-001"}},
)
for msg in result["messages"]:
    t = type(msg).__name__
    c = str(msg.content)[:300]
    print(f"[{t}] {c}\n")
